<span class="line">			<span class="token function">Optional</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">			<span class="token function">Nillable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">		field<span class="token punctuation">.</span><span class="token function">Enum</span><span class="token punctuation">(</span><span class="token string">"type"</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">			<span class="token function">Comment</span><span class="token punctuation">(</span><span class="token string">"消息类型"</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">			<span class="token function">NamedValues</span><span class="token punctuation">(</span></span>
